function getServiceKey(){return sessionStorage.getItem("wf_service_key")||prompt("Enter Supabase service role key (from Project Settings → API):")}const STORAGE_BUCKET="site-photos";async function api(e,t){var o=await fetch(SUPABASE_URL+e,{...t,headers:{apikey:SUPABASE_ANON_KEY,Authorization:"Bearer "+getServiceKey(),...t?t.headers:{}}});if(!o.ok){var i=await o.text();throw new Error(i)}return o.json()}async function loadPhotos(){var e=document.getElementById("photo-list");e.innerHTML='<p style="color:var(--muted);">Loading photos...</p>';try{var t=await api("/rest/v1/site_images?order=section.asc,position.asc&select=*");if(!t.length)return void(e.innerHTML='<p style="color:var(--muted);text-align:center;padding:40px;">No photos uploaded yet.</p>');var o="",i="";t.forEach(function(e){var t=SUPABASE_URL+"/storage/v1/object/public/site-photos/"+e.file_path;e.section!==i&&(i=e.section,o+='<h3 style="margin:24px 0 12px;text-transform:capitalize;">'+e.section+'</h3><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:12px;">'),o+='<div style="position:relative;border:1px solid var(--border);border-radius:8px;overflow:hidden;aspect-ratio:1;"><img src="'+t+'" alt="'+e.alt_text+'" style="width:100%;height:100%;object-fit:cover;"><button onclick="deletePhoto(\''+e.id+'\')" style="position:absolute;top:4px;right:4px;background:#DC2626;color:#fff;border:none;border-radius:4px;padding:4px 8px;font-size:12px;cursor:pointer;min-width:auto;min-height:auto;">&times;</button><div style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,0.6);color:#fff;font-size:11px;padding:4px 8px;">'+e.position+"</div></div>"}),e.innerHTML=o}catch(t){e.innerHTML='<p style="color:#DC2626;">Failed to load photos: '+t.message+"</p>"}}async function uploadPhoto(){var e=document.getElementById("photo-file").files[0];if(!e)return alert("Select a photo first.");if(e.size>10485760)return alert("File too large. Max size is 10MB.");if(!["image/jpeg","image/png","image/webp"].includes(e.type))return alert("File type not allowed. Use JPEG, PNG, or WebP.");var t=document.getElementById("photo-section").value,o=parseInt(document.getElementById("photo-position").value)||0,i=document.getElementById("photo-alt").value||e.name,a=e.name.split(".").pop(),r=t+"/"+Date.now()+"."+a,n=document.getElementById("upload-btn");n.disabled=!0,n.textContent="Uploading...";try{var s=await fetch(SUPABASE_URL+"/storage/v1/object/site-photos/"+r,{method:"POST",headers:{Authorization:"Bearer "+getServiceKey()},body:e});if(!s.ok)throw new Error("Upload failed: "+await s.text());await api("/rest/v1/site_images",{method:"POST",headers:{"Content-Type":"application/json",Prefer:"return=minimal"},body:JSON.stringify({section:t,position:o,file_path:r,alt_text:i})}),document.getElementById("photo-form").reset(),loadPhotos(),alert("Photo uploaded!")}catch(e){alert("Error: "+e.message)}finally{n.disabled=!1,n.textContent="Upload"}}async function deletePhoto(e){if(confirm("Delete this photo?"))try{var t=await api("/rest/v1/site_images?id=eq."+e+"&select=file_path");if(t.length){var o=t[0].file_path;await fetch(SUPABASE_URL+"/storage/v1/object/site-photos/"+o,{method:"DELETE",headers:{Authorization:"Bearer "+getServiceKey()}})}await api("/rest/v1/site_images?id=eq."+e,{method:"DELETE"}),loadPhotos()}catch(e){alert("Error: "+e.message)}}